<style>#contact-us-section{margin-top:25px}#contact-us-section .contact-us-section{min-height:100px;margin-bottom:-50px;z-index:2;position:relative;border-radius:20px;padding:25px 35px}#contact-us-section .contact-us-section .contact-us-kicker{font-size:16px;color:#ec1e28;line-height:1.2em}#contact-us-section .contact-us-section .contact-text{font-size:34px;font-weight:600;max-width:600px;line-height:1.3em;margin:10px 0}footer{position:relative;background:#222431;color:#e4eff0;border-radius:50px 50px 0 0}footer a{color:#e4eff0;text-decoration:none}footer a:hover{color:#e4eff0;text-decoration:underline}footer .footer-content{padding:100px 40px 50px 40px;display:-webkit-box;display:-webkit-flex;display:-moz-box;display:-ms-flexbox;display:flex;font-size:14px;line-height:1.3em;-webkit-box-align:start;-webkit-align-items:flex-start;-moz-box-align:start;-ms-flex-align:start;align-items:flex-start;-webkit-box-pack:start;-webkit-justify-content:flex-start;-moz-box-pack:start;-ms-flex-pack:start;justify-content:flex-start}footer .footer-content h3{font-size:18px;font-weight:700}footer .footer-content .get-in-touch{width:30%}footer .footer-content .follow-us{width:15%}footer .footer-content .follow-us ul{display:-webkit-box;display:-webkit-flex;display:-moz-box;display:-ms-flexbox;display:flex;-webkit-box-align:center;-webkit-align-items:center;-moz-box-align:center;-ms-flex-align:center;align-items:center;-webkit-box-pack:start;-webkit-justify-content:flex-start;-moz-box-pack:start;-ms-flex-pack:start;justify-content:flex-start;padding:0;margin:0;gap:10px;list-style:none}footer .footer-content .follow-us ul li a{font-size:27px}footer .footer-content .site-map{width:20%}footer .footer-content .site-map ul{padding:0;margin:0;list-style:none}footer .footer-content .site-map ul li{display:-webkit-box;display:-webkit-flex;display:-moz-box;display:-ms-flexbox;display:flex;-webkit-box-align:center;-webkit-align-items:center;-moz-box-align:center;-ms-flex-align:center;align-items:center;gap:10px;margin-bottom:10px;-webkit-box-pack:start;-webkit-justify-content:flex-start;-moz-box-pack:start;-ms-flex-pack:start;justify-content:flex-start}footer .footer-content .site-map ul li:before{content:'';background:#ec1e27;width:3px;height:3px;border-radius:100%;display:block}footer .footer-content .latest-news{width:20%}footer .footer-content .latest-news .newsletter{margin-top:10px;position:relative}footer .footer-content .latest-news .newsletter input{border:1px solid #e4eff0;border-radius:23px;color:#e4eff0;background:#222431}footer .footer-content .latest-news .newsletter a{position:absolute;right:2px;top:2px;background:#ec1e27;font-size:19px;padding:7px 9px;border-radius:100%}@media (max-width:767px){footer .footer-content{padding:25px 0;-webkit-flex-wrap:wrap;-ms-flex-wrap:wrap;flex-wrap:wrap}footer .footer-content .tp-logo{width:100%;text-align:center}footer .footer-content .quick-links{width:100%;max-width:unset;margin-right:0}footer .footer-content .quick-links ul{display:-webkit-box;display:-webkit-flex;display:-moz-box;display:-ms-flexbox;display:flex;-webkit-box-align:center;-webkit-align-items:center;-moz-box-align:center;-ms-flex-align:center;align-items:center;-webkit-box-pack:justify;-webkit-justify-content:space-between;-moz-box-pack:justify;-ms-flex-pack:justify;justify-content:space-between;margin:25px 0}footer .footer-content .quick-links ul li{text-align:center}footer .footer-content .contact-us{width:100%;text-align:center}}footer .copyright{background:222431;font-size:12px;padding:0 40px 20px}footer .copyright .img-logo{max-width:125px}footer .copyright .img-logo img{width:100%}</style>